0(N) -  Current max of priority.
* Define priority (index of char in order string).
* Iterate the text , if char is NOT part of order text then skip else
** If cur_priority < max_priority return false;
** else max_priority = cur_priority;

```
public class Solution {

    boolean isValidOrder(String order, String text) {
        Map<Character, Integer> priority = new HashMap<>();
        for(int i = 0 ; i < order.length(); i++) {
            priority.put(order.charAt(i), i);
        }
        int maxPriority = -1;
        for(int i =0 ; i < text.length(); i++) {
            char c = text.charAt(i);
            if(priority.get(c)==null)
                continue;
            if(maxPriority > priority.get(c))
                return false;
            maxPriority = priority.get(c);
        }
        return true;
    }

    public static void main(String args[]) {
        String order = "abcd";
        String valid = "axubbxcxxd";
        String invalid = "axubbxucxuubxxxd";
        System.out.println("Answer = " + new Solution().isValidOrder(order, valid));
        System.out.println("Answer = " + new Solution().isValidOrder(order, invalid));
    }
}
