How are ties handled? For "abcd" pattern, is "abcdd" valid or not?
Is input all lowercase chars? If so you can use a 26 length array or even a single int with bitmasks if you want to be fancy instead of a set.

Here's my solution assuming ties should be invalid. If ties are valid then you'd need to keep track of last inserted char into set.
```
#include<bits/stdc++.h>
using namespace std;

bool isValid(string& pattern, string& tomatch) {
  int i = 0;
  int n = tomatch.length();
  unordered_set<char> seen;
  for (char ch: tomatch) {
    if (seen.find(ch) != seen.end()) {
      return false;
    }
    if (i<n && ch == pattern[i]) {
      seen.insert(ch);
      i++;
    }
  }
  return true;
}

int main() {
  string pattern = "abcd";
  string tomatch = "axubbxcxbxd";
  // ans = invalid
  cout << isValid(pattern, tomatch) << "\n";

  pattern = "abcd";
  tomatch = "abceeeed";
  // ans = valid
  cout << isValid(pattern, tomatch) << "\n";

  pattern = "abcd";
  tomatch = "abcdd";
  // ans = invalid
  cout << isValid(pattern, tomatch) << "\n";
  return 0;
}

