I have a slight different approach to solve this problem.

We maintain a `res` string and initialize it as empty string. Maintain an unordered_set `s` for every character in pattern.

For every character in string `tomatch`, if the character is present in the set `s`, we push it to the end of `res` string. if the character matches last character in res string, its still a valid order but we skip adding it to `res` as we want only distinct chars in `res`. 

In the end we compare `res` with `pattern`. As all the chars in `res` are distinct and in order of pattern the string `res` should be equal to `pattern`.

```
// #include`  <bits/stdc++.h> -> Reformat this line, leetcode not letting me post header.

using namespace std;

bool isValid(string pattern, string tomatch) {
	// Assumptions
	// 1. All characters in pattern string are distinct.
	unordered_set<char> s;
	for(char c: pattern) {
		s.insert(c);
	}

	string res = "";
	for(char c: tomatch) {
		if(s.find(c) !== s.end()) {
			if(res.length() == 0) {
				res.push_back(c);
			} else if (res[res.length()-1] != c) {
				res.push_back(c);
			}
		}
	}

	return res.equals(pattern);

}

int main() {
	string pattern = "abcd";
	string tomatch = "axubbxcxbxd";

	if(isValid(pattern, tomatch)) {
		cout<<"Valid String"<<endl;
	} else {
		cout<<"Invalid String"<<endl;
	}
	return 0;
}
